const resp = $.steps.searchEmails.response || {};
const data = resp.data || resp;
const messages = data.messages || data.items || [];
const maxEmails = $.input.maxEmails || 15;
const limited = messages.slice(0, maxEmails);

const emailIds = limited.map(m => m.id || m.messageId || '');
return { emailIds, totalFound: messages.length, processing: emailIds.length };

const iterations = $.steps.fetchEmailDetails.response.iterations || [];

let allEmails = '';
let successCount = 0;

iterations.forEach((iter, i) => {
  const resp = (iter.getEmail && iter.getEmail.response) ? iter.getEmail.response : null;
  const emailData = resp ? (resp.data || resp) : null;

  if (emailData) {
    successCount++;
    const headers = emailData.payload ? emailData.payload.headers || [] : [];
    const subject = headers.find(h => (h.name || '').toLowerCase() === 'subject');
    const from = headers.find(h => (h.name || '').toLowerCase() === 'from');
    const date = headers.find(h => (h.name || '').toLowerCase() === 'date');
    const snippet = emailData.snippet || '';

    allEmails += '=== EMAIL ' + (i + 1) + ' ===\n';
    allEmails += 'Subject: ' + (subject ? subject.value : 'N/A') + '\n';
    allEmails += 'From: ' + (from ? from.value : 'N/A') + '\n';
    allEmails += 'Date: ' + (date ? date.value : 'N/A') + '\n';
    allEmails += 'Preview: ' + snippet.slice(0, 300) + '\n\n';
  }
});

return { allEmails, successCount };

const emailData = $.steps.compileEmails.output;
const categories = $.input.categories || 'work, personal, newsletter, marketing, billing, notification, spam';

let prompt = 'You are an email management specialist. Categorize, prioritize, and summarize the following emails.\n\n';
prompt += 'AVAILABLE CATEGORIES: ' + categories + '\n\n';
prompt += 'EMAILS:\n' + emailData.allEmails + '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Categorize each email into one of the available categories\n';
prompt += '- Assign priority: high, medium, or low\n';
prompt += '- Write a 1-2 sentence summary\n';
prompt += '- Extract any action items\n';
prompt += '- Flag potential spam or phishing\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "emails": [\n';
prompt += '    {\n';
prompt += '      "from": "sender",\n';
prompt += '      "subject": "subject line",\n';
prompt += '      "date": "date",\n';
prompt += '      "category": "work",\n';
prompt += '      "priority": "high",\n';
prompt += '      "summary": "Brief summary",\n';
prompt += '      "actionItems": ["action needed"],\n';
prompt += '      "isSpam": false\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "stats": {\n';
prompt += '    "total": 0,\n';
prompt += '    "highPriority": 0,\n';
prompt += '    "categories": { "work": 0, "personal": 0 },\n';
prompt += '    "spamDetected": 0\n';
prompt += '  },\n';
prompt += '  "overallSummary": "Brief overview of inbox state"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiClassify.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { emails: [], stats: { total: 0, highPriority: 0, categories: {}, spamDetected: 0 }, overallSummary: raw }; }

const ai = $.steps.parseAI.output;
const stats = ai.stats || {};
const emails = ai.emails || [];

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Email Filter + Summary Report', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Total Processed:*\n' + (stats.total || emails.length) },
  { type: 'mrkdwn', text: '*High Priority:*\n' + (stats.highPriority || 0) }
] });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Spam Detected:*\n' + (stats.spamDetected || 0) },
  { type: 'mrkdwn', text: '*Status:*\n:white_check_mark: Complete' }
] });

if (stats.categories) {
  let catText = '*Categories:* ';
  const catEntries = Object.entries(stats.categories);
  catEntries.forEach(([cat, count]) => { catText += cat + ': ' + count + '  '; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: catText } });
}

blocks.push({ type: 'divider' });

const highPriority = emails.filter(e => e.priority === 'high');
if (highPriority.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*:rotating_light: High Priority Emails:*' } });
  highPriority.slice(0, 5).forEach(e => {
    let text = '*' + (e.subject || 'No subject') + '*';
    text += '\nFrom: ' + (e.from || 'Unknown') + ' | Category: ' + (e.category || 'N/A');
    text += '\n' + (e.summary || '');
    if (e.actionItems && e.actionItems.length > 0) {
      text += '\n:point_right: ' + e.actionItems.join(', ');
    }
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text.slice(0, 1800) } });
  });
  blocks.push({ type: 'divider' });
}

const otherEmails = emails.filter(e => e.priority !== 'high');
if (otherEmails.length > 0) {
  let otherText = '*Other Emails:*\n';
  otherEmails.slice(0, 8).forEach(e => {
    const icon = e.priority === 'medium' ? ':large_blue_circle:' : ':white_circle:';
    otherText += icon + ' [' + (e.category || 'N/A') + '] ' + (e.subject || 'No subject') + ' - ' + (e.summary || '').slice(0, 80) + '\n';
  });
  if (otherEmails.length > 8) otherText += '... and ' + (otherEmails.length - 8) + ' more';
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: otherText.slice(0, 1800) } });
}

if (ai.overallSummary) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Overview:*\n' + ai.overallSummary.slice(0, 500) } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Gmail + Claude AI + Google Sheets' }] });

const fallback = 'Email Summary: ' + (stats.total || 0) + ' processed, ' + (stats.highPriority || 0) + ' high priority';
return { blocks, fallback };
